 namespace WPAICG\Chat\Initializer; if (!defined('ABSPATH')) { exit; } function load_ajax_handlers_logic(): void { $base_path = WPAICG_PLUGIN_DIR . 'classes/chat/'; $ajax_handlers_paths = [ 'admin/ajax/chatbot_ajax_handler.php', 'admin/ajax/conversation_ajax_handler.php', 'admin/ajax/class-aipkit-chatbot-image-ajax-handler.php', ]; foreach ($ajax_handlers_paths as $handler_path_relative) { $full_path = $base_path . $handler_path_relative; $class_name_base = basename($handler_path_relative, '.php'); $class_name_parts = explode('-', str_replace('class-aipkit-', '', $class_name_base)); $class_name = '\\WPAICG\\Chat\\Admin\\Ajax\\'; foreach ($class_name_parts as $part) { $class_name .= ucfirst($part); } if ($handler_path_relative === 'admin/ajax/class-aipkit-chatbot-image-ajax-handler.php') { $class_name = '\\WPAICG\\Chat\\Admin\\Ajax\\ChatbotImageAjaxHandler'; } elseif ($handler_path_relative === 'admin/ajax/chatbot_ajax_handler.php') { $class_name = '\\WPAICG\\Chat\\Admin\\Ajax\\ChatbotAjaxHandler'; } elseif ($handler_path_relative === 'admin/ajax/conversation_ajax_handler.php') { $class_name = '\\WPAICG\\Chat\\Admin\\Ajax\\ConversationAjaxHandler'; } if (file_exists($full_path) && !class_exists($class_name)) { require_once $full_path; } } } 